export const fetchMainBoardScanning = async (apiKey: string): Promise<AnalysisResult> => { const ai = new GoogleGenAI({ apiKey }); const now = new Date(); const dateStr = now.toLocaleDateString('zh-CN'); const prompt = `【核心指令：全量沪深主板涨停标的扫描 - 杜绝截断】当前现实日期: ${dateStr}。请利用 googleSearch 检索【今日即 ${dateStr}】沪深主板真实封死涨停的标的。[!!! 绝对任务清单 !!!]：1. **数量要求**：严禁只返回 5-6 只。主板行情好的时候通常有几十只涨停，请务必返回今日最核心、最具题材代表性的 **20-30 只** 标的。2. **强制校验**：万科A (000002)、中国联通等大盘股，如果今日只是“异动”而非“涨停”，绝对不允许出现在名单中。AI 必须核实其今日收盘价对应的真实涨幅是否 > 9.8%。3. **真实性锚定**：搜索词应使用 "A股${dateStr}涨停全貌"、"${dateStr} 沪深京涨停股一览"。如果没有检索到今日的完整表格，请结合多个搜索结果进行拼凑还原，确保覆盖面最广。`; const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: prompt, config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json", responseSchema: mainBoardScanSchema } }); const parsed = robustParse(response.text || "{}"); return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, isStructured: true, mainBoardScanData: parsed, market: MarketType.CN }; };
