export const fetchStockDetailWithImage = async (base64Image: string, query: string, market: MarketType, apiKey: string, currentPrice?: string): Promise<AnalysisResult> => { const ai = new GoogleGenAI({ apiKey }); const now = new Date(); const timeContext = now.toLocaleString('zh-CN'); const prompt = `作为顶级 A 股量化交易专家，请对标的 "${query}" (市场: ${market}) 进行深度量化研判。【核心任务：视觉对齐与指标纠正】你面前有一张该标的的实时行情截图。1. **强制识别盘面价格**: 请优先 from 图中提取最新的【现价】、【涨跌幅】、【成交额/量】。2. **量价关系审计**: 观察图中成交量柱状图，判断当前形态是“放量攻击”、“缩量回调”还是“高位分歧”。3. **均线形态校准**: 识别 K 线与均线（MA5/10/20/60）的相对位置，判断是否存在明显的支撑或乖离率过大的情况。[!!! 绝对优先级逻辑 !!!]: 1. 如果用户手动指定了现价 (${currentPrice || '未手动指定'})，则以该价格为最高优先级。2. 否则，必须提取【截图中的视觉价格】作为逻辑基准进行后续诊断。3. 联网搜索 (googleSearch) 的数据仅用于补充行业背景、近期利好/利空公告。**严禁使用搜索到的滞后价格覆盖截图中的实时视觉数据**。参考盘面时间: ${timeContext}请输出详细诊断报告，包含：- 视觉提取指标 (现价、量能评分、K线位置)- 关键压力与支撑位 (结合图中形态提取)- 量化择时指令 (加仓/减仓/持有/观望)- 核心研判逻辑 (必须详细说明图中形态对判断的支撑作用)`; const parts = [ { text: prompt }, { inlineData: { mimeType: 'image/jpeg', data: base64Image } } ]; const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: { parts }, config: { tools: [{ googleSearch: {} }] } }); return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, market }; };
export const parseBrokerageScreenshot = async (base64Image: string, apiKey?: string): Promise<HoldingsSnapshot> => { const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY }); const imagePart = { inlineData: { mimeType: 'image/jpeg', data: base64Image } }; const textPart = { text: "解析截图中的持仓数据，输出 JSON。" }; const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: { parts: [imagePart, textPart] }, config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties: { totalAssets: { type: Type.NUMBER }, positionRatio: { type: Type.NUMBER }, date: { type: Type.STRING }, holdings: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, code: { type: Type.STRING }, volume: { type: Type.NUMBER }, costPrice: { type: Type.NUMBER }, currentPrice: { type: Type.NUMBER }, profit: { type: Type.NUMBER }, profitRate: { type: Type.STRING }, marketValue: { type: Type.NUMBER } } } } } } } }); return robustParse(response.text || "{}"); };
export const fetchPeriodicReview = async (journals: any[], label: string, market: MarketType, apiKey?: string): Promise<AnalysisResult> => { const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY }); const prompt = `对以下历史交易记录进行【${label}】阶段性复盘：${JSON.stringify(journals)}`; const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: prompt, config: { responseMimeType: "application/json", responseSchema: periodicReviewSchema } }); const parsed = robustParse(response.text || "{}"); return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, isStructured: true, periodicData: parsed, market }; };
export const extractTradingPlan = async (content: string, apiKey?: string): Promise<{ items: PlanItem[], summary: string }> => { const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY }); const prompt = `从以下分析文本中提取具体的交易计划项：\n\n${content}`; const response = await ai.models.generateContent({ model: GEMINI_MODEL_PRIMARY, contents: prompt, config: { responseMimeType: "application/json", responseSchema: tradingPlanSchema } }); const parsed = robustParse(response.text || "{}"); return { items: parsed.items?.map((it: any) => ({ ...it, id: Math.random().toString(36).substr(2, 9), status: 'pending' })) || [], summary: parsed.summary || "" }; };
